const buffer = new ArrayBuffer(4);
const intView = new Uint32Array(buffer);
const floatView = new Float32Array(buffer);
var combined = 0;
var data = {};

function readFloat(hi, lo) {
  intView[0] = (hi << 16) | lo;
  return floatView[0].toFixed(3);
}

// U1 - reg 0
data["U1"]    = readFloat(msg.payload[0],  msg.payload[1]);
// U2 - reg 2
data["U2"]    = readFloat(msg.payload[2],  msg.payload[3]);
// U3 - reg 4
data["U3"]    = readFloat(msg.payload[4],  msg.payload[5]);
// I1 - reg 6
data["I1"]    = readFloat(msg.payload[6],  msg.payload[7]);
// I2 - reg 8
data["I2"]    = readFloat(msg.payload[8],  msg.payload[9]);
// I3 - reg 10
data["I3"]    = readFloat(msg.payload[10], msg.payload[11]);
// P1 - reg 12
data["P1"]    = readFloat(msg.payload[12], msg.payload[13]);
// P2 - reg 14
data["P2"]    = readFloat(msg.payload[14], msg.payload[15]);
// P3 - reg 16
data["P3"]    = readFloat(msg.payload[16], msg.payload[17]);
// S1 - reg 18
data["S1"]    = readFloat(msg.payload[18], msg.payload[19]);
// S2 - reg 20
data["S2"]    = readFloat(msg.payload[20], msg.payload[21]);
// S3 - reg 22
data["S3"]    = readFloat(msg.payload[22], msg.payload[23]);
// Q1 - reg 24
data["Q1"]    = readFloat(msg.payload[24], msg.payload[25]);
// Q2 - reg 26
data["Q2"]    = readFloat(msg.payload[26], msg.payload[27]);
// Q3 - reg 28
data["Q3"]    = readFloat(msg.payload[28], msg.payload[29]);
// PF1 - reg 30  ← was foutief data["Q1"]
data["PF1"]   = readFloat(msg.payload[30], msg.payload[31]);
// PF2 - reg 32  ← was foutief data["Q2"]
data["PF2"]   = readFloat(msg.payload[32], msg.payload[33]);
// PF3 - reg 34  ← was foutief data["Q3"]
data["PF3"]   = readFloat(msg.payload[34], msg.payload[35]);
// PT  - reg 52
data["PT"]    = readFloat(msg.payload[52], msg.payload[53]);
// QT  - reg 60
data["QT"]    = readFloat(msg.payload[60], msg.payload[61]);
// PFT - reg 62
data["PFT"]   = readFloat(msg.payload[62], msg.payload[63]);
// PimpT - reg 72
data["PimpT"] = readFloat(msg.payload[72], msg.payload[73]);
// PexpT - reg 74
data["PexpT"] = readFloat(msg.payload[74], msg.payload[75]);
// QimpT - reg 76
data["QimpT"] = readFloat(msg.payload[76], msg.payload[77]);
// QexpT - reg 78
data["QexpT"] = readFloat(msg.payload[78], msg.payload[79]);

var nmsg = {};
nmsg.topic = 'telemetry';
nmsg.payload = data;
return nmsg;

let mid = global.get("mid") || 0;

const Dev = "ASSET"; // <-- jouw asset ID

const idMapping = {
    "U1":    3000,
    "U2":    3100,
    "U3":    3200,
    "I1":    3300,
    "I2":    3400,
    "I3":    3500,
    "P1":    3600,
    "P2":    3700,
    "P3":    3800,
    "S1":    3850,
    "S2":    3860,
    "S3":    3870,
    "Q1":    3900,
    "Q2":    4000,
    "Q3":    4100,
    "PF1":   4150,
    "PF2":   4160,
    "PF3":   4170,
    "PT":    4200,
    "QT":    4300,
    "PFT":   4400,
    "PexpT": 4500,
    "PimpT": 4600,
    "QimpT": 4700,
    "QexpT": 4800
};

const mappingLower = {};
Object.keys(idMapping).forEach(k => mappingLower[k.toLowerCase()] = idMapping[k]);

let result = {
    MID: mid,
    D: [{
        Dev: Dev,
        ED: [],
        MD: []
    }]
};

const payloadData = msg.payload || {};

for (let key in payloadData) {
    if (!payloadData.hasOwnProperty(key)) continue;

    let id = idMapping[key];
    if (typeof id === "undefined") {
        id = mappingLower[key.toLowerCase()];
    }

    if (typeof id !== "undefined") {
        let rawVal = payloadData[key];
        if (rawVal === null || typeof rawVal === "object") {
            node.warn(`Overslaan ${key}: waarde is geen primitief`);
            continue;
        }
        let num = parseFloat(String(rawVal).trim().replace(",", "."));
        if (!Number.isFinite(num)) {
            node.warn(`Ongeldige waarde voor ${key}: "${rawVal}" — overslaan`);
            continue;
        }
        result.D[0].MD.push({ Id: id, Val: num });
    } else {
        node.debug(`Key niet in mapping: ${key}`);
    }
}

result.D[0].TS = new Date().toISOString();

if (result.D[0].MD.length > 0) {
    global.set("mid", mid + 1);
}

msg.payload = result;
msg.queque = "success";
return msg;

if (msg.error) {
  msg.failReason = msg.error;
  return [null, msg];
}

if (!Array.isArray(msg.payload)) {
  msg.failReason = `payload_not_array (${typeof msg.payload})`;
  return [null, msg];
}

if (msg.payload.length !== 80) {
  msg.failReason = `bad_length (${msg.payload.length})`;
  return [null, msg];
}

if (msg.payload.every(v => v === 0)) {
  msg.failReason = "all_zero_payload";
  return [null, msg];
}

return [msg, null];

let mid = global.get("mid") || 0;

const Dev = "ASSET"; // <-- zelfde asset ID
const MODBUS_FAIL_EVENT_ID = 7199;

let reason = msg.failReason || msg.error || "MODBUS_FAIL";

const unitId = msg.unitId ?? msg.queueUnitId ?? undefined;
const qLen = msg.queueLengthByUnitId?.queueLength ?? msg.queueLength ?? undefined;

let details = [];
if (unitId !== undefined) details.push(`unitId=${unitId}`);
if (qLen  !== undefined) details.push(`queueLen=${qLen}`);
if (msg.topic)     details.push(`topic=${msg.topic}`);
if (msg.messageId) details.push(`messageId=${msg.messageId}`);

let val = String(reason);
if (details.length) val += ` | ${details.join(", ")}`;

const result = {
  MID: mid,
  D: [{
    Dev: Dev,
    TS: new Date().toISOString(),
    ED: [{ Id: MODBUS_FAIL_EVENT_ID, Val: val, Sev: 2 }],
    MD: []
  }]
};

global.set("mid", mid + 1);

msg.payload = result;
msg.queque  = "fail";
msg.topic   = "telemetry";
return msg;

const DELAY_MS = 7500;
const MAX_RETRY = 6;

const Dev = "ASSET";
const RETRY_WARN_EVENT_ID = 7198;

let q = (msg.queque || "").toLowerCase();
let retry = global.get("retry") || 0;

function sendLater(out1, out2, out3) {
  setTimeout(() => node.send([out1, out2, out3]), DELAY_MS);
}

if (q === "fail") {
  retry += 1;
  global.set("retry", retry);

  if (retry < MAX_RETRY) {
    sendLater({ ...msg, action: "go", retry }, null, null);
    return;
  }

  global.set("retry", 0);
  sendLater(null, { ...msg, action: "stop", retry: MAX_RETRY }, null);
  return;
}

if (q === "success") {
  const retriesUsed = retry;

  if (retriesUsed <= 1) {
    global.set("retry", 0);
    sendLater(null, { ...msg, action: "ok", retry: 0 }, null);
    return;
  }

  global.set("retry", 0);

  const m2 = { ...msg, action: "ok_but_retried", info: `success but retried ${retriesUsed} times`, retriesUsed, retry: 0 };

  const mid = global.get("mid") || 0;
  global.set("mid", mid + 1);

  const m3 = {
    topic: "telemetry",
    queque: "event",
    payload: {
      MID: mid,
      D: [{
        Dev,
        TS: new Date().toISOString(),
        ED: [{ Id: RETRY_WARN_EVENT_ID, Val: `success but retried ${retriesUsed} times`, Sev: 2 }],
        MD: []
      }]
    }
  };

  sendLater(null, m2, m3);
  return;
}

sendLater(null, { ...msg, action: "unknown_queque", retry }, null);
